sql:
SELECT AVG(close) AS average_close_price
FROM daily_stock_data
WHERE ticker = 'AAPL' AND date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT ticker, company_name, AVG(market_capitalization) AS avg_market_cap
FROM stocks
GROUP BY ticker, company_name;

SELECT market_capitalization
FROM stocks
WHERE ticker = 'AAPL';

SELECT AVG(market_capitalization) AS average_market_cap
FROM stocks
WHERE sector = 'Technology';

SELECT AVG(adj_close) AS average_adj_close
FROM daily_stock_data
WHERE ticker = '1';

external_knowledge:
- 'AAPL' is the ticker symbol for Apple Inc., often metaphorically referred to as the 'golden apple' in financial markets;
- Adjusted closing price accounts for any corporate actions affecting the stock price;
- The peak value represents the highest point of the stock's adjusted closing price.

sql:
SELECT MAX(adj_close) AS peak_adj_close
FROM daily_stock_data
WHERE ticker = 'AAPL';
